export function reorganizarGrupos(equipos) {
    const primera = distribuirPrimeraRFEF(equipos);
    const segunda = distribuirSegundaRFEF(equipos);
    const tercera = distribuirTerceraRFEF(equipos);
    const superiores = equipos.filter(e => ["La Liga", "Liga 2"].includes(e.liga));

    return [...superiores, ...primera, ...segunda, ...tercera];
}

function distribuirPrimeraRFEF(equipos) {
    const candidatos = equipos.filter(e => e.liga === "Primera RFEF");

    const norte = ["Galicia", "Asturias", "Cantabria", "País Vasco", "Navarra", "Castilla y León", "La Rioja", "Aragón"];
    let grupo1 = [];
    let grupo2 = [];

    // Agrupamos por cercanía
    candidatos.forEach(e => {
        if (norte.includes(e.comunidad)) grupo1.push(e);
        else grupo2.push(e);
    });

    // Balancear si hay desequilibrio
    while (grupo1.length > 20) grupo2.push(grupo1.pop());
    while (grupo2.length > 20) grupo1.push(grupo2.pop());

    grupo1.forEach(e => e.liga = "Primera RFEF - Grupo 1");
    grupo2.forEach(e => e.liga = "Primera RFEF - Grupo 2");

    return [...grupo1, ...grupo2];
}

const comunidadesPorGrupo = {
    1: ["Galicia", "Asturias", "Cantabria", "Castilla y León"],
    2: ["País Vasco", "Navarra", "La Rioja"],
    3: ["Cataluña", "Comunidad Valenciana", "Aragón", "Islas Baleares"],
    4: ["Andalucía", "Extremadura", "Murcia"],
    5: ["Madrid", "Castilla-La Mancha", "Canarias"]
};

function distribuirSegundaRFEF(equipos) {
    const candidatos = equipos.filter(e => e.liga === "Segunda RFEF");
    const grupos = { 1: [], 2: [], 3: [], 4: [], 5: [] };

    candidatos.forEach(e => {
        for (let g in comunidadesPorGrupo) {
            if (comunidadesPorGrupo[g].includes(e.comunidad)) {
                grupos[g].push(e);
                return;
            }
        }
    });

    // Completar hasta 18 por grupo (usando excedentes de otros grupos si es necesario)
    let todos = candidatos.filter(e => true);
    for (let g = 1; g <= 5; g++) {
        while (grupos[g].length < 18) {
            const e = todos.find(eq => !Object.values(grupos).some(arr => arr.includes(eq)));
            if (!e) break;
            grupos[g].push(e);
        }
        grupos[g].forEach(e => e.liga = `Segunda RFEF - Grupo ${g}`);
    }

    return Object.values(grupos).flat();
}

function distribuirTerceraRFEF(equipos) {
    const candidatos = equipos.filter(e => e.liga === "Tercera RFEF");
    const regionales = equipos.filter(e => e.liga.startsWith("Regionales"));

    const grupos = {};

    // Agrupar por comunidad
    [...candidatos, ...regionales].forEach(e => {
        const c = e.comunidad;
        if (!grupos[c]) grupos[c] = [];
        grupos[c].push(e);
    });

    // Completar hasta 18 equipos
    const finales = [];
    for (let comunidad in grupos) {
        const lista = grupos[comunidad].slice(0, 18);
        lista.forEach(e => e.liga = `Tercera RFEF - ${comunidad}`);
        finales.push(...lista);
    }

    return finales;
}
